svg.script:

const timelineData = {
    'birds': { 
        title: 'Observations of Nature', 
        date: 'Prehistory', 
        desc: 'Long before engineering, early humans observed the spinning, autorotating fall of maple seeds (samaras) and the hovering capabilities of birds and insects, sparking the first dreams of vertical flight.' 
    },
    'flying-top': { 
        title: 'The Chinese Flying Top (Bamboo Copter)', 
        date: 'c. 400 BC', 
        desc: 'Widely considered the first human-made device to achieve rotary-wing flight. By rapidly rubbing a stick attached to angled bamboo blades, kinetic energy generated aerodynamic lift, sending the toy flying upward.' 
    },
    'da-vinci': { 
        title: 'Leonardo da Vinci\'s Aerial Screw', 
        date: '1489', 
        desc: 'The great Renaissance polymath sketched a design for a human-powered machine with a helical linen rotor. While it was much too heavy to actually fly, it remains the first recorded engineering concept resembling a helicopter.' 
    },
    'lomonosov': { 
        title: 'Mikhail Lomonosov\'s Coaxial Rotor', 
        date: 'July 1754', 
        desc: 'Russian polymath Mikhail Lomonosov demonstrated a small, working tandem/coaxial rotor model to the Russian Academy of Sciences. Powered by a wound-up watch spring, it was intended to lift meteorological instruments.' 
    },
    'cornu': { 
        title: 'Paul Cornu\'s First Manned Hover', 
        date: 'November 13, 1907', 
        desc: 'French engineer Paul Cornu achieved what is widely recognized as the first free flight of a rotary-wing aircraft carrying a pilot. His twin-rotor machine lifted about 1 foot off the ground for 20 seconds, though it lacked directional control.' 
    },
    'autogyro': { 
        title: 'Juan de la Cierva\'s Autogyro', 
        date: 'January 9, 1923', 
        desc: 'Cierva successfully flew the C.4 Autogyro. By using a standard airplane propeller for forward thrust and allowing the top rotor to spin freely in the wind (autorotation), he solved the devastating issue of dissymmetry of lift.' 
    },
    'fw-61': { 
        title: 'Focke-Wulf Fw 61', 
        date: 'June 26, 1936', 
        desc: 'Designed by Henrich Focke, this was the world\'s first practical, fully controllable helicopter. It featured twin side-by-side rotors and demonstrated precise hovering, forward, backward, and sideways flight.' 
    },
    'vs-300': { 
        title: 'Vought-Sikorsky VS-300', 
        date: 'September 14, 1939', 
        desc: 'Igor Sikorsky successfully tether-flew his VS-300. This groundbreaking aircraft pioneered the now-standard configuration: a single main lifting rotor to fly, and a single vertical tail rotor to counteract torque.' 
    },
    'r-4': { 
        title: 'Sikorsky R-4 Mass Production', 
        date: '1942', 
        desc: 'The Sikorsky R-4 became the world\'s first large-scale mass-produced helicopter and the first helicopter to enter service with the United States military, establishing the foundation of the modern rotorcraft industry.' 
    },
    'bell-47': { 
        title: 'Bell 47 Commercial Certification', 
        date: 'March 8, 1946', 
        desc: 'Designed by Arthur M. Young and featuring his revolutionary stabilizing bar, the Bell 47 received the first-ever commercial helicopter certification. It pioneered medical evacuation, news broadcasting, and civilian rotary flight.' 
    },
    'v-22': { 
        title: 'Bell Boeing V-22 Osprey', 
        date: 'March 19, 1989', 
        desc: 'The V-22 Osprey became the first successful production tiltrotor aircraft. By physically tilting its wing-mounted proprotors, it combines the vertical takeoff and hover capabilities of a helicopter with the speed and range of a fixed-wing turboprop airplane.' 
    }
};

function selectEvent(id) {
    // 1. Clear previous active states
    document.querySelectorAll('.interactive-node').forEach(el => el.classList.remove('active'));

    // 2. Get data for selected event
    const eventData = timelineData[id];
    if (!eventData) return;

    // 3. Update the info panel text
    document.getElementById('info-title').textContent = eventData.title;
    document.getElementById('info-date').textContent = eventData.date;
    document.getElementById('info-desc').textContent = eventData.desc;

    // 4. Highlight the selected node
    const nodeGroup = document.getElementById('group-' + id);
    if (nodeGroup) {
        nodeGroup.classList.add('active');
    }
}
